import { describe, it, expect, afterEach } from 'vitest';
import WebSocket from 'ws';
import type {
  ProjectId,
  ProjectEntry,
  ProjectSummary,
  DeliveryState,
  ExecutionPlan,
  ServerWSMessage,
  StateTransition,
  Result,
} from '../../shared/types.js';
import { ok, err, deriveProjectSummary } from '../../shared/types.js';
import {
  createSubscriptionServer,
  type SubscriptionServer,
  type SubscriptionServerDeps,
} from '../index.js';

// --- Fixtures ---

const makeProjectId = (id: string): ProjectId => id as ProjectId;

const makeState = (status = 'pending'): DeliveryState => ({
  schema_version: '1.0',
  created_at: '2026-03-01T00:00:00Z',
  updated_at: '2026-03-01T00:00:00Z',
  plan_path: '.nw-teams/plan.yaml',
  current_layer: 1,
  summary: { total_steps: 1, total_layers: 1, completed: 0, failed: 0, in_progress: 0 },
  steps: {
    '01-01': {
      step_id: '01-01',
      name: 'Test step',
      layer: 1,
      status: status as DeliveryState['steps'][string]['status'],
      teammate_id: null,
      started_at: null,
      completed_at: null,
      review_attempts: 0,
      files_to_modify: [],
    },
  },
  teammates: {},
});

const makePlan = (): ExecutionPlan => ({
  schema_version: '1.0',
  summary: { total_steps: 1, total_layers: 1, max_parallelism: 1, requires_worktrees: false },
  layers: [{
    layer: 1,
    parallel: false,
    use_worktrees: false,
    steps: [{ step_id: '01-01', name: 'Test step', files_to_modify: [] }],
  }],
});

const makeEntry = (id: string, status = 'pending'): ProjectEntry => ({
  projectId: makeProjectId(id),
  state: makeState(status),
  plan: makePlan(),
});

// --- Test helpers ---

interface TestClient {
  readonly ws: WebSocket;
  readonly messages: ServerWSMessage[];
  readonly waitForMessage: (count: number) => Promise<void>;
}

const connectTestClient = (port: number): Promise<TestClient> =>
  new Promise((resolve, reject) => {
    const messages: ServerWSMessage[] = [];
    let resolveWait: (() => void) | null = null;
    let waitTarget = 0;

    const ws = new WebSocket(`ws://localhost:${port}`);

    ws.on('message', (data) => {
      messages.push(JSON.parse(data.toString()) as ServerWSMessage);
      if (resolveWait && messages.length >= waitTarget) {
        resolveWait();
        resolveWait = null;
      }
    });

    const waitForMessage = (count: number): Promise<void> => {
      if (messages.length >= count) return Promise.resolve();
      waitTarget = count;
      return new Promise((r) => { resolveWait = r; });
    };

    ws.on('open', () => resolve({ ws, messages, waitForMessage }));
    ws.on('error', reject);
  });

const delay = (ms: number): Promise<void> =>
  new Promise((resolve) => setTimeout(resolve, ms));

const sendClientMessage = (ws: WebSocket, message: object): void => {
  ws.send(JSON.stringify(message));
};

// --- Deps factory using in-memory store ---

const createTestDeps = (entries: ProjectEntry[] = []): SubscriptionServerDeps => {
  const store = new Map<ProjectId, ProjectEntry>(
    entries.map((e) => [e.projectId, e]),
  );

  return {
    getProject: (projectId: ProjectId): Result<ProjectEntry, string> => {
      const entry = store.get(projectId);
      return entry ? ok(entry) : err(`Not found: ${projectId}`);
    },
    listProjectSummaries: (): readonly ProjectSummary[] =>
      [...store.values()].map((e) => deriveProjectSummary(e.projectId, e.state)),
  };
};

// --- Tests ---

describe('SubscriptionServer', () => {
  let server: SubscriptionServer | null = null;
  const testClients: TestClient[] = [];

  afterEach(async () => {
    for (const tc of testClients) {
      if (tc.ws.readyState === WebSocket.OPEN) {
        tc.ws.close();
      }
    }
    testClients.length = 0;
    if (server) {
      await server.close();
      server = null;
    }
  });

  it('should send project_list on initial connection', async () => {
    const entryA = makeEntry('alpha');
    const deps = createTestDeps([entryA]);
    server = createSubscriptionServer(0, deps);
    await server.ready;

    const client = await connectTestClient(server.port);
    testClients.push(client);

    await client.waitForMessage(1);

    const msg = client.messages[0];
    expect(msg.type).toBe('project_list');
    if (msg.type !== 'project_list') return;
    expect(msg.projects).toHaveLength(1);
    expect(msg.projects[0].projectId).toBe('alpha');
  });

  it('should send init with state and plan when client subscribes to a project', async () => {
    const entry = makeEntry('beta');
    const deps = createTestDeps([entry]);
    server = createSubscriptionServer(0, deps);
    await server.ready;

    const client = await connectTestClient(server.port);
    testClients.push(client);
    await client.waitForMessage(1); // project_list

    sendClientMessage(client.ws, { type: 'subscribe', projectId: 'beta' });
    await client.waitForMessage(2); // init

    const msg = client.messages[1];
    expect(msg.type).toBe('init');
    if (msg.type !== 'init') return;
    expect(msg.projectId).toBe('beta');
    expect(msg.state).toEqual(entry.state);
    expect(msg.plan).toEqual(entry.plan);
  });

  it('should broadcast update only to clients subscribed to that project', async () => {
    const entryA = makeEntry('proj-a');
    const entryB = makeEntry('proj-b');
    const deps = createTestDeps([entryA, entryB]);
    server = createSubscriptionServer(0, deps);
    await server.ready;

    const clientA = await connectTestClient(server.port);
    const clientB = await connectTestClient(server.port);
    testClients.push(clientA, clientB);

    await Promise.all([clientA.waitForMessage(1), clientB.waitForMessage(1)]);

    // clientA subscribes to proj-a, clientB subscribes to proj-b
    sendClientMessage(clientA.ws, { type: 'subscribe', projectId: 'proj-a' });
    sendClientMessage(clientB.ws, { type: 'subscribe', projectId: 'proj-b' });
    await Promise.all([clientA.waitForMessage(2), clientB.waitForMessage(2)]);

    // Broadcast update for proj-a only
    const updatedState = makeState('in_progress');
    const transitions: readonly StateTransition[] = [{
      step_id: '01-01',
      from_status: 'pending',
      to_status: 'in_progress',
      teammate_id: null,
      timestamp: '2026-03-01T01:00:00Z',
    }];
    server.notifyProjectUpdate(makeProjectId('proj-a'), updatedState, transitions);

    await clientA.waitForMessage(3); // should receive update
    await delay(100); // give clientB time to NOT receive anything

    expect(clientA.messages[2].type).toBe('update');
    if (clientA.messages[2].type === 'update') {
      expect(clientA.messages[2].projectId).toBe('proj-a');
      expect(clientA.messages[2].state).toEqual(updatedState);
      expect(clientA.messages[2].transitions).toHaveLength(1);
    }
    // clientB should only have project_list + init (no update for proj-a)
    expect(clientB.messages).toHaveLength(2);
  });

  it('should not broadcast when transitions are empty', async () => {
    const entry = makeEntry('gamma');
    const deps = createTestDeps([entry]);
    server = createSubscriptionServer(0, deps);
    await server.ready;

    const client = await connectTestClient(server.port);
    testClients.push(client);
    await client.waitForMessage(1);

    sendClientMessage(client.ws, { type: 'subscribe', projectId: 'gamma' });
    await client.waitForMessage(2);

    // Broadcast with empty transitions
    server.notifyProjectUpdate(makeProjectId('gamma'), makeState(), []);
    await delay(100);

    expect(client.messages).toHaveLength(2); // project_list + init only
  });

  it('should stop sending updates after unsubscribe', async () => {
    const entry = makeEntry('delta');
    const deps = createTestDeps([entry]);
    server = createSubscriptionServer(0, deps);
    await server.ready;

    const client = await connectTestClient(server.port);
    testClients.push(client);
    await client.waitForMessage(1);

    sendClientMessage(client.ws, { type: 'subscribe', projectId: 'delta' });
    await client.waitForMessage(2);

    sendClientMessage(client.ws, { type: 'unsubscribe', projectId: 'delta' });
    await delay(50); // let unsubscribe process

    const transitions: readonly StateTransition[] = [{
      step_id: '01-01',
      from_status: 'pending',
      to_status: 'in_progress',
      teammate_id: null,
      timestamp: '2026-03-01T01:00:00Z',
    }];
    server.notifyProjectUpdate(makeProjectId('delta'), makeState('in_progress'), transitions);
    await delay(100);

    expect(client.messages).toHaveLength(2); // project_list + init only
  });

  it('should broadcast project_list to all connected clients on notifyProjectListChange', async () => {
    const entry = makeEntry('one');
    const deps = createTestDeps([entry]);
    server = createSubscriptionServer(0, deps);
    await server.ready;

    const client1 = await connectTestClient(server.port);
    const client2 = await connectTestClient(server.port);
    testClients.push(client1, client2);

    await Promise.all([client1.waitForMessage(1), client2.waitForMessage(1)]);

    server.notifyProjectListChange();

    await Promise.all([client1.waitForMessage(2), client2.waitForMessage(2)]);

    expect(client1.messages[1].type).toBe('project_list');
    expect(client2.messages[1].type).toBe('project_list');
  });

  it('should ignore invalid JSON messages from client', async () => {
    const entry = makeEntry('epsilon');
    const deps = createTestDeps([entry]);
    server = createSubscriptionServer(0, deps);
    await server.ready;

    const client = await connectTestClient(server.port);
    testClients.push(client);
    await client.waitForMessage(1);

    // Send invalid JSON
    client.ws.send('not-json');
    // Send valid JSON but wrong shape
    client.ws.send(JSON.stringify({ type: 'unknown' }));
    // Send subscribe without projectId
    client.ws.send(JSON.stringify({ type: 'subscribe' }));

    await delay(100);

    // Should only have the initial project_list
    expect(client.messages).toHaveLength(1);
  });

  it('should clean up subscriptions when client disconnects', async () => {
    const entry = makeEntry('zeta');
    const deps = createTestDeps([entry]);
    server = createSubscriptionServer(0, deps);
    await server.ready;

    const client = await connectTestClient(server.port);
    testClients.push(client);
    await client.waitForMessage(1);

    sendClientMessage(client.ws, { type: 'subscribe', projectId: 'zeta' });
    await client.waitForMessage(2);

    // Disconnect client
    client.ws.close();
    await delay(100);

    // Broadcast should not throw
    const transitions: readonly StateTransition[] = [{
      step_id: '01-01',
      from_status: 'pending',
      to_status: 'in_progress',
      teammate_id: null,
      timestamp: '2026-03-01T01:00:00Z',
    }];
    expect(() => {
      server!.notifyProjectUpdate(makeProjectId('zeta'), makeState('in_progress'), transitions);
    }).not.toThrow();
  });
});

